import{_ as a,o as t,c as r,ag as o}from"./chunks/framework.CnqOxlWO.js";const u=JSON.parse('{"title":"Recharge","description":"","frontmatter":{},"headers":[],"relativePath":"features/recharge.md","filePath":"features/recharge.md","lastUpdated":1773376681000}'),i={name:"features/recharge.md"};function n(s,e,l,h,c,d){return t(),r("div",null,[...e[0]||(e[0]=[o('<h1 id="recharge" tabindex="-1">Recharge <a class="header-anchor" href="#recharge" aria-label="Permalink to &quot;Recharge&quot;">​</a></h1><p>ClawdSaber uses a <strong>credit system</strong> to pay for model usage. When your credits run low, you can top up from the Recharge page.</p><h2 id="what-the-recharge-page-offers" tabindex="-1">What the Recharge Page Offers <a class="header-anchor" href="#what-the-recharge-page-offers" aria-label="Permalink to &quot;What the Recharge Page Offers&quot;">​</a></h2><ul><li>Current credit balance display</li><li>Amount selection</li><li>Order creation and payment flow</li><li>Order history</li><li>Model pricing reference</li></ul><h2 id="step-1-select-an-amount" tabindex="-1">Step 1: Select an Amount <a class="header-anchor" href="#step-1-select-an-amount" aria-label="Permalink to &quot;Step 1: Select an Amount&quot;">​</a></h2><p>When you open the Recharge page, you will see preset amounts:</p><ul><li><strong>10 USDT</strong></li><li><strong>50 USDT</strong></li><li><strong>100 USDT</strong></li></ul><p>You can also enter a custom amount.</p><h3 id="limits" tabindex="-1">Limits <a class="header-anchor" href="#limits" aria-label="Permalink to &quot;Limits&quot;">​</a></h3><ul><li>The minimum recharge amount is <strong>1 USDT</strong>.</li><li>The page estimates how many credits you will receive based on the current exchange rate.</li></ul><h2 id="step-2-create-an-order" tabindex="-1">Step 2: Create an Order <a class="header-anchor" href="#step-2-create-an-order" aria-label="Permalink to &quot;Step 2: Create an Order&quot;">​</a></h2><p>After selecting an amount, click the recharge button to create an order.</p><p>The app switches to the payment waiting screen, which shows:</p><ul><li>Receiving address</li><li>Amount to send</li><li>Network</li><li>Estimated credits</li><li>Order number</li><li>Remaining time</li></ul><h2 id="step-3-send-payment" tabindex="-1">Step 3: Send Payment <a class="header-anchor" href="#step-3-send-payment" aria-label="Permalink to &quot;Step 3: Send Payment&quot;">​</a></h2><p>Send the exact amount to the displayed address using the correct network.</p><p>The two most important things:</p><ol><li><strong>Amount must match exactly.</strong></li><li><strong>Network must be correct.</strong></li></ol><p>Using the wrong network may result in lost funds, even if the address looks correct.</p><h2 id="step-4-wait-for-confirmation" tabindex="-1">Step 4: Wait for Confirmation <a class="header-anchor" href="#step-4-wait-for-confirmation" aria-label="Permalink to &quot;Step 4: Wait for Confirmation&quot;">​</a></h2><p>The Recharge page automatically polls the order status. You do not need to refresh manually.</p><p>Additional behaviors:</p><ul><li>If you return to the Recharge page while a pending order exists, the app resumes that order automatically.</li><li>After a successful payment, your credit balance updates automatically.</li></ul><h2 id="order-history" tabindex="-1">Order History <a class="header-anchor" href="#order-history" aria-label="Permalink to &quot;Order History&quot;">​</a></h2><p>The bottom of the Recharge page shows your order history.</p><p>Orders have three possible statuses:</p><ul><li><strong>Credited</strong> — payment received and credits added</li><li><strong>Expired</strong> — the order timed out before payment was detected</li><li><strong>Pending</strong> — waiting for payment</li></ul><p>You can click a pending order to return to its payment screen.</p><h2 id="model-pricing-reference" tabindex="-1">Model Pricing Reference <a class="header-anchor" href="#model-pricing-reference" aria-label="Permalink to &quot;Model Pricing Reference&quot;">​</a></h2><p>The Recharge page also includes a model pricing table that shows:</p><ul><li>Official price</li><li>Platform price</li><li>Discount percentage</li><li>Input credit cost</li><li>Output credit cost</li></ul><p>This is useful for estimating how far your credits will go.</p><h2 id="common-mistakes" tabindex="-1">Common Mistakes <a class="header-anchor" href="#common-mistakes" aria-label="Permalink to &quot;Common Mistakes&quot;">​</a></h2><h3 id="amount-too-small" tabindex="-1">Amount too small <a class="header-anchor" href="#amount-too-small" aria-label="Permalink to &quot;Amount too small&quot;">​</a></h3><p>Orders cannot be created for amounts below 1 USDT.</p><h3 id="wrong-network" tabindex="-1">Wrong network <a class="header-anchor" href="#wrong-network" aria-label="Permalink to &quot;Wrong network&quot;">​</a></h3><p>Always use the network displayed on the payment screen. Do not mix networks.</p><h3 id="order-expired" tabindex="-1">Order expired <a class="header-anchor" href="#order-expired" aria-label="Permalink to &quot;Order expired&quot;">​</a></h3><p>If an order expires, you must create a new one. Expired orders cannot be reused.</p><p>If you encounter payment issues, check the <a href="/clawdsaber-docs/settings/faq.html">FAQ</a>.</p>',40)])])}const m=a(i,[["render",n]]);export{u as __pageData,m as default};
